import os, yaml, json

kb_path = '/tmp/selfservice-repo/data/knowledge'
result = {'operation': [], 'noc': [], 'customer': []}

for root, _, files in os.walk(kb_path):
    for f in files:
        if f.endswith('.yaml'):
            filepath = os.path.join(root, f)
            with open(filepath, 'r', encoding='utf-8') as stream:
                try:
                    data = yaml.safe_load(stream) or {}
                    file_default = data.get('default_audience', ['operation'])

                    # Ensure file_default is valid list, else fallback to ['operation'] (Default Deny)
                    if not isinstance(file_default, list):
                        file_default = ['operation']

                    cats = data.get('categories', {})
                    for cat_id, cat_val in cats.items():
                        sections = cat_val.get('sections', {})
                        for sec_id, sec_val in sections.items():
                            entries = sec_val.get('entries', [])
                            for entry in entries:
                                audience = entry.get('audience', file_default)
                                if not isinstance(audience, list):
                                    audience = ['operation']

                                item = {
                                    'id': entry.get('id'),
                                    'intent': entry.get('intent'),
                                    'answer': entry.get('answer'),
                                    'keywords': entry.get('keywords', []),
                                    'refs': entry.get('refs', [])
                                }

                                if 'operation' in audience:
                                    result['operation'].append(item)
                                if 'noc' in audience:
                                    result['noc'].append(item)
                                if 'customer' in audience:
                                    result['customer'].append(item)
                except Exception as e:
                    pass

print(json.dumps(result))
"

